window.PACTO.acts["reg-2014-515"]={"label": "REGOLAMENTO (UE) N. 515/2014 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 515/2014", "file": "ext-reg-2014-515.html", "external": true, "version": "consolidato 2020-03-28", "eurlex": "https://eur-lex.europa.eu/eli/reg/2014/515/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e ambito di applicazione", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento istituisce lo strumento di sostegno finanziario per la gestione delle frontiere esterne e la politica comune dei visti (lo «strumento») nell’ambito del Fondo sicurezza interna (il «Fondo»).</div>\n</div>"], [null, "<p class=\"norm\">Unitamente al regolamento (UE) n. 513/2014, il presente regolamento istituisce il Fondo per il periodo dal 1<span class=\"superscript\">o</span> gennaio 2014 al 31 dicembre 2020.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente regolamento stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi del sostegno finanziario e le azioni ammissibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il quadro generale di attuazione delle azioni ammissibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le risorse disponibili a valere sul presente strumento, nel periodo dal 1<span class=\"superscript\">o</span> gennaio 2014 al 31 dicembre 2020, e la loro ripartizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ambito di applicazione e l’obiettivo dei diversi mezzi specifici attraverso i quali è finanziata la spesa per la gestione delle frontiere esterne e la politica comune in materia di visti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presente regolamento prevede l’applicazione delle norme di cui al regolamento (UE) n. 514/2014.</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«frontiere esterne» : le frontiere terrestri degli Stati membri, comprese le frontiere fluviali e lacustri, le frontiere marittime e gli aeroporti, i porti fluviali, i porti marittimi e lacustri cui si applica il diritto dell’Unione relativo all’attraversamento delle frontiere esterne, siano esse temporanee o meno;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«norme comuni dell’Unione» : l’applicazione comune e non frammentaria di misure operative al fine di ottenere un livello di sicurezza elevato e uniforme in materia di controllo alle frontiere e di visti in conformità del regolamento (CE) n. 562/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n), del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n), del regolamento (CE) n. 767/2008 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n), del regolamento (CE) n. 2007/2004, del regolamento (CE) n. 1931/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n), del catalogo Schengen sui controlli alle frontiere esterne, del manuale pratico per le guardie di frontiera, del manuale sui visti, del manuale EUROSUR e di tutti gli altri regolamenti e linee guida da adottare a livello dell’Unione per quanto riguarda il controllo alle frontiere e i visti;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«frontiere esterne temporanee» : </p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il confine comune fra uno Stato membro che attua integralmente l’acquis di Schengen e uno Stato membro che è tenuto ad applicarlo integralmente in conformità del suo atto di adesione, ma per il quale non è entrata in vigore la relativa decisione del Consiglio che lo autorizza a applicare tale acquis in misura integrale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il confine comune fra due Stati membri tenuti ad applicare integralmente l’acquis di Schengen in conformità dei rispettivi atti di adesione, ma per i quali non è ancora entrata in vigore la relativa decisione del Consiglio che li autorizza a applicare tale acquis in misura integrale;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«valico di frontiera» : qualsiasi valico autorizzato dalle autorità competenti per l’attraversamento delle frontiere esterne, comunicato a norma dell’articolo 34, paragrafo 2, del regolamento (CE) n. 562/2006;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«meccanismo di valutazione e monitoraggio Schengen» : la verifica della corretta applicazione dell’acquis di Schengen, come stabilita dal regolamento (UE) n. 1053/2013;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«situazione di emergenza» : situazione risultante da un’urgente ed eccezionale pressione migratoria in cui si verifica – o si potrebbe verificare – un afflusso massiccio o sproporzionato di cittadini di paesi terzi attraverso le frontiere esterne di uno o più Stati membri o qualsiasi altra situazione d’emergenza debitamente circostanziata che richieda un intervento urgente alle frontiere esterne;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sezione frontiere esterne» : la totalità o una parte della frontiera terrestre o marittima esterna di uno Stato membro quale definita dal diritto nazionale o determinata dal centro di coordinamento nazionale o qualsiasi altra autorità nazionale competente ai fini dell’attuazione del regolamento (UE) n 1052/2013.</p>\n</td>\n</tr>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Obiettivi", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’obiettivo generale dello strumento è contribuire a garantire un elevato livello di sicurezza nell’Unione facilitando i viaggi legittimi, attraverso un livello uniforme ed elevato di controllo delle frontiere esterne e il trattamento efficace dei visti Schengen, conformemente all’impegno dell’Unione nei confronti delle libertà fondamentali e dei diritti umani.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito dell’obiettivo generale di cui al paragrafo 1, lo strumento, in conformità delle priorità individuate nelle pertinenti strategie, nei programmi e nelle valutazioni dei rischi e delle minacce dell’Unione, contribuisce ai seguenti obiettivi specifici:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere una politica comune in materia di visti per facilitare i viaggi legittimi delle persone, fornire un servizio di elevata qualità ai richiedenti il visto, assicurare parità di trattamento dei cittadini di paesi terzi e contrastare l’immigrazione illegale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere la gestione integrata delle frontiere, anche promuovendo un’ulteriore armonizzazione delle misure relative alla gestione delle frontiere conformemente alle norme comuni dell’Unione e mediante la condivisione delle informazioni tra Stati membri nonché tra gli Stati membri e Frontex, in modo da assicurare, da un lato, un livello elevato e uniforme di controllo e protezione delle frontiere esterne, anche contrastando l’immigrazione illegale, e, dall’altro, l’attraversamento agevole delle frontiere esterne conformemente all’acquis di Schengen, garantendo nel contempo l’accesso alla protezione internazionale a quanti ne necessitino, in conformità con gli obblighi assunti dagli Stati membri nel settore dei diritti umani, compreso il principio di non respingimento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il raggiungimento degli obiettivi specifici dello strumento è valutato a norma dell’articolo 55, paragrafo 2, del regolamento (UE) n. 514/2014 attraverso indicatori comuni di cui all’allegato IV del presente regolamento e indicatori specifici per programma inclusi nei programmi nazionali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per conseguire gli obiettivi di cui ai paragrafi 1 e 2, lo strumento contribuisce ai seguenti obiettivi operativi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere l’elaborazione, l’attuazione e l’applicazione di politiche volte a garantire l’assenza di qualsiasi controllo sulle persone, a prescindere dalla cittadinanza, all’atto dell’attraversamento delle frontiere interne e a effettuare il controllo delle persone e la sorveglianza efficace dell’attraversamento delle frontiere esterne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituire progressivamente un sistema integrato di gestione delle frontiere esterne, basato sulla solidarietà e la responsabilità, in particolare mediante:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rafforzamento dei controlli alle frontiere esterne e dei sistemi di sorveglianza e della cooperazione interforze tra le guardie di frontiera, le dogane, le autorità competenti in materia di immigrazione e asilo e le autorità di contrasto degli Stati membri alle frontiere esterne, incluse quelle marittime.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure da attuare sul territorio in relazione alla gestione delle frontiere esterne e le necessarie misure di accompagnamento in materia di sicurezza dei documenti, gestione delle identità e interoperabilità delle attrezzature tecniche acquisite;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali misure che contribuiscano anche alla prevenzione e alla lotta contro la criminalità transfrontaliera alle frontiere esterne correlata alla circolazione delle persone, compresi la tratta e il traffico di esseri umani;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere lo sviluppo e l’attuazione della politica comune in materia di visti e altri titoli di soggiorno di breve durata, e di forme diverse di cooperazione consolare al fine di assicurare una migliore copertura consolare e prassi armonizzate in materia di emissione di visti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costituire e operare sistemi informatici, le relative infrastrutture di comunicazione e attrezzature che sostengano la politica comune dei visti, i controlli alle frontiere e la sorveglianza di frontiera alle frontiere esterne e rispettino pienamente il diritto in materia di protezione dei dati personali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare la consapevolezza situazionale alle frontiere esterne e le capacità di reazione degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurare l’efficiente ed uniforme applicazione dell’acquis dell’Unione in materia di frontiere e visti, compreso il corretto funzionamento del meccanismo di valutazione e monitoraggio Schengen;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare le azioni degli Stati membri che contribuiscono a potenziare la cooperazione tra gli Stati membri che operano nei paesi terzi in relazione ai flussi di cittadini di paesi terzi verso il territorio degli Stati membri, anche nella prevenzione e nel contrasto dell’immigrazione illegale, e la cooperazione con i paesi terzi a tal riguardo in piena coerenza con gli obiettivi e i principi dell’azione esterna e della politica umanitaria dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le azioni finanziate nell’ambito dello strumento sono attuate nel pieno rispetto dei diritti fondamentali e della dignità umana. In particolare, le azioni rispettano le disposizioni della Carta dei diritti fondamentali dell’Unione europea, il diritto dell’Unione in materia di protezione dei dati, la Convenzione europea per la salvaguardia dei diritti dell’uomo e delle libertà fondamentali (CEDU), il principio di equo trattamento dei cittadini dei paesi terzi, il diritto di asilo e di protezione internazionale, il principio di non respingimento e gli obblighi internazionali dell’Unione e degli Stati membri derivanti dagli strumenti internazionali di cui sono firmatari, quale la Convenzione di Ginevra relativa allo status dei rifugiati del 28 luglio 1951, integrata dal protocollo di New York del 31 gennaio 1967.</div>\n</div>"], [null, "<p class=\"norm\">In particolare, laddove possibile, nell’attuazione delle misure gli Stati membri prestano particolare attenzione all’identificazione, all’assistenza immediata e alla consegna ai servizi di protezione delle persone vulnerabili, in particolare i minori e i minori non accompagnati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nell’attuare le misure finanziate nell’ambito dello strumento che sono legate alla sorveglianza delle frontiere marittime, gli Stati membri prestano particolare attenzione ai loro obblighi ai sensi del diritto marittimo internazionale volti a fornire assistenza alle persone in difficoltà. A questo proposito, le apparecchiature e i sistemi supportati nell’ambito dello strumento possono essere utilizzati per affrontare situazioni di ricerca e soccorso che possono presentarsi durante un’operazione di sorveglianza di frontiera in mare, contribuendo in tal modo a garantire la protezione e a salvare la vita dei migranti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo strumento contribuisce anche al finanziamento dell’assistenza tecnica su iniziativa degli Stati membri o della Commissione.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Azioni ammissibili", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito degli obiettivi di cui all’articolo 3 del presente regolamento, e alla luce dell’esito del dialogo politico di cui all’articolo 13 del regolamento (UE) n. 514/2014 e in linea con gli obiettivi del programma nazionale di cui all’articolo 9 del presente regolamento, lo strumento sostiene azioni negli Stati membri o condotte dagli Stati membri e in particolare quelle elencate di seguito:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">infrastrutture, edifici e sistemi necessari ai valichi di frontiera e per la sorveglianza fra i valichi di frontiera per prevenire e affrontare attraversamenti di frontiera non autorizzati, l’immigrazione clandestina e la criminalità transfrontaliera, nonché per garantire flussi di viaggio agevoli;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attrezzatura operativa, mezzi di trasporto e sistemi di comunicazione necessari per un controllo di frontiera efficace e sicuro e il rilevamento di persone;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sistemi informatici e di comunicazione per la gestione efficace dei flussi migratori transfrontalieri, inclusi gli investimenti in sistemi esistenti e futuri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">infrastrutture, edifici, sistemi informatici e di comunicazione e attrezzatura operativa necessaria per il trattamento delle domande di visto e la cooperazione consolare e per altre azioni volte a migliorare la qualità del servizio ai richiedenti il visto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formazione in merito all’utilizzo delle attrezzature e dei sistemi di cui alle lettere b), c) e d) e promozione di standard di gestione della qualità, nonché formazione delle guardie di frontiera, eventualmente anche in paesi terzi, riguardo all’esecuzione dei loro compiti di sorveglianza, consulenza e controllo in conformità con le norme internazionali sui diritti umani, compresa l’identificazione delle vittime della tratta e del traffico di esseri umani;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">distaccamento di ufficiali di collegamento competenti nel settore dell’immigrazione e consulenti in materia di documenti nei paesi terzi nonché scambio e distaccamento di guardie di frontiera tra Stati membri o tra uno Stato membro e un paese terzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi, formazione, progetti pilota e altre azioni che istituiscono progressivamente un sistema integrato di gestione delle frontiere esterne, di cui all’articolo 3, paragrafo 3, comprese le azioni volte a promuovere la cooperazione tra le agenzie sia all’interno degli Stati membri che tra Stati membri e azioni in materia di interoperabilità e armonizzazione dei sistemi di gestione delle frontiere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi, progetti pilota e azioni volte ad attuare le raccomandazioni, gli standard operativi e le migliori prassi derivanti dalla cooperazione operativa fra gli Stati membri e le agenzie dell’Unione;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito degli obiettivi di cui all’articolo 3 del presente regolamento, e alla luce dell’esito del dialogo strategico di cui all’articolo 13 del regolamento (UE) n. 514/2014 e in linea con gli obiettivi del programma nazionale di cui all’articolo 9 del presente regolamento, lo strumento sostiene altresì azioni nei paesi terzi e in relazione a tali paesi, aventi in particolare le seguenti finalità:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sistemi di informazione, strumenti o attrezzature per lo scambio di informazioni tra gli Stati membri e i paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni relative alla cooperazione operativa tra gli Stati membri e i paesi terzi, comprese le operazioni congiunte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">progetti in paesi terzi finalizzati a migliorare i sistemi di sorveglianza per assicurare la cooperazione con EUROSUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi, seminari, laboratori, conferenze, formazione, attrezzature e progetti pilota per fornire consulenze tecniche e operative ad hoc ai paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">studi, seminari, laboratori, conferenze, formazione, attrezzature e progetti pilota per attuare le specifiche raccomandazioni, gli standard operativi e le migliori prassi derivanti dalla cooperazione operativa fra gli Stati membri e le agenzie dell’Unione nei paesi terzi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione e gli Stati membri, unitamente al Servizio europeo per l’azione esterna, assicurano il coordinamento per quanto concerne le azioni nei paesi terzi e in relazione a tali paesi, come previsto all’articolo 3, paragrafo 5, del regolamento (UE) n. 514/2014.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le azioni di cui al paragrafo 1, lettera a), non sono ammissibili alle frontiere esterne temporanee.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le azioni relative al ripristino temporaneo ed eccezionale del controllo di frontiera alle frontiere interne, ai sensi del codice frontiere Schengen, non sono ammissibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le azioni il cui scopo o effetto esclusivo è il controllo delle merci non sono ammissibili.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Risorse globali e attuazione", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le risorse globali per l’attuazione dello strumento ammontano a 2 760  milioni di EUR a prezzi correnti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo e il Consiglio autorizzano gli stanziamenti annuali nei limiti del quadro finanziario pluriennale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le risorse globali sono attuate mediante:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i programmi nazionali, di cui agli articoli 9 e 12;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sostegno operativo, nell’ambito dei programmi nazionali e alle condizioni stabilite nell’articolo 10;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il regime di transito speciale, di cui all’articolo 11;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni dell’Unione, di cui all’articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza emergenziale, di cui all’articolo 14;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di un programma volto a introdurre sistemi informatici per la gestione dei flussi migratori attraverso le frontiere esterne alle condizioni stabilite nell’articolo 15;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza tecnica, di cui all’articolo 16.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La dotazione di bilancio a titolo dello strumento assegnata alle azioni dell’Unione di cui all’articolo 13 del presente regolamento, all’assistenza emergenziale di cui all’articolo 14 del presente regolamento e all’assistenza tecnica di cui all’articolo 16, paragrafo 1, del presente regolamento, è attuata in gestione diretta a norma dell’articolo 58, paragrafo 1, lettera a), del regolamento (UE, Euratom) n. 966/2012 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n) e, se del caso, in gestione indiretta a norma dell’articolo 58, paragrafo 1, lettera c), del regolamento (UE, Euratom) n. 966/2012.</div>\n</div>"], [null, "<p class=\"norm\">La dotazione di bilancio assegnata ai programmi nazionali di cui all’articolo 9, al sostegno operativo di cui all’articolo 10 e al funzionamento del regime di transito speciale di cui all’articolo 11, è attuata in gestione congiunta a norma dell’articolo 58, paragrafo 1, lettera b), del regolamento (UE, Euratom) n. 966/2012.</p>"], [null, "<p class=\"norm\">La dotazione di bilancio assegnata ai paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen di cui al paragrafo 7 del presente articolo è attuata in gestione indiretta ai sensi dell’articolo 58, paragrafo 1, lettera c), punto i), del regolamento (UE, Euratom) n. 966/2012.</p>"], [null, "<p class=\"norm\">Le modalità di esecuzione del bilancio per il programma relativo allo sviluppo di sistemi informatici basati su sistemi attuali e/o nuovi sono stabilite nei pertinenti atti legislativi dell’Unione previa loro adozione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le risorse globali sono così utilizzate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1 551  milioni di EUR per i programmi nazionali degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">791 milioni di EUR per lo sviluppo di sistemi informatici basati su sistemi esistenti e/o nuovi a sostegno della gestione dei flussi migratori attraverso le frontiere esterne previa adozione dei pertinenti atti legislativi dell’Unione;</p>\n<p class=\"list\">Qualora tale importo non sia assegnato o speso, la Commissione, mediante un atto delegato ai sensi dell’articolo 17, lo riassegna a una o più attività di cui all’articolo 6, paragrafo 1, lettere b) e c), e al presente paragrafo. Tale atto delegato comprende una valutazione dell’evoluzione dei sistemi informatici pertinenti, comprendente l’esecuzione del bilancio e gli importi non spesi previsti. La riassegnazione può avvenire in seguito all’adozione dei pertinenti atti legislativi o in occasione della revisione intermedia di cui all’articolo 8.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">154 milioni di EUR per il regime di transito speciale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">264 milioni di EUR per le azioni dell’Unione, l’assistenza emergenziale e l’assistenza tecnica su iniziativa della Commissione, di cui almeno il 30 % è utilizzato per le azioni dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Congiuntamente alle risorse globali previste per il regolamento (UE) n. 513/2014, le risorse globali assegnate allo strumento, stabilite al paragrafo 1, costituiscono la dotazione finanziaria del Fondo e fungono da riferimento privilegiato per il Parlamento europeo e il consiglio, nel corso della procedura di bilancio annuale, ai sensi del punto 17 dell’accordo interistituzionale, del 2 dicembre 2013, tra il Parlamento europeo, il Consiglio e la Commissione sulla disciplina di bilancio, sulla cooperazione in materia di bilancio e sulla sana gestione finanziaria (\n<span class=\"superscript\">6</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen partecipano allo strumento a norma del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Sono conclusi accordi contenenti le disposizioni relative al contributo finanziario di tali paesi allo strumento e le disposizioni complementari necessarie in relazione a detta partecipazione, in particolare disposizioni che tutelino gli interessi finanziari dell’Unione e il potere di controllo della Corte dei conti.</p>"], [null, "<p class=\"norm\">I contributi finanziari provenienti da tali paesi si aggiungono alle risorse globali stanziate dal bilancio dell’Unione di cui al paragrafo 1.</p>"]]}, "6": {"label": "Articolo 6", "heading": "Risorse per le azioni ammissibili negli Stati membri", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A titolo indicativo agli Stati membri è assegnato un importo pari a 1 551  milioni di EUR, così ripartito:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1 276  milioni di EUR come indicato all’allegato I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">147 milioni di EUR, sulla base dei risultati del meccanismo di cui all’articolo 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nell’ambito della revisione intermedia di cui all’articolo 8 e per il periodo a decorrere dall’esercizio 2018, 128 milioni di EUR, il rimanente degli stanziamenti disponibili in base al presente articolo, o altro importo determinato ai sensi del paragrafo 2, sulla base dei risultati dell’analisi dei rischi e della revisione intermedia.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni Stato membro assegna gli importi di base per i programmi nazionali indicati nell’allegato I come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 10 % alle azioni relative all’articolo 9, paragrafo 2, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 25 % alle azioni relative all’articolo 9, paragrafo 2, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 5 % alle azioni relative all’articolo 9, paragrafo 2, lettere c), d), e) e f).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono discostarsi da tali percentuali minime purché motivino la loro scelta nel programma nazionale spiegando perché l’assegnazione di risorse inferiori a tali minimi non pregiudica il conseguimento del pertinente obiettivo. La Commissione valuterà tale motivazione nel quadro della sua approvazione dei programmi nazionali di cui all’articolo 9, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri destinano a EUROSUR i finanziamenti necessari per garantirne il buon funzionamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Durante la fase di sviluppo del sistema europeo di informazione e autorizzazione ai viaggi (ETIAS) gli Stati membri ricevono un importo aggiuntivo di 96,5 milioni di EUR rispetto all’importo di base, che assegnano interamente all’ETIAS per garantirne lo sviluppo rapido ed efficace in coerenza con l’attuazione del sistema centrale ETIAS secondo quanto previsto nel regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">7</span>\n).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per onorare degnamente gli obiettivi dello strumento in caso di circostanze impreviste o dell’emergere di nuove circostanze e/o per garantire l’efficiente attuazione dei finanziamenti disponibili ai sensi dello strumento, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 17 per adattare l’importo indicativo di cui al paragrafo 1, lettera c), del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che aderiranno all’Unione nel periodo 2012-2020 non beneficiano degli stanziamenti per i programmi nazionali nell’ambito dello strumento nella misura in cui beneficiano di uno strumento temporaneo dell’Unione che sostiene il finanziamento negli Stati membri beneficiari di azioni lungo le nuove frontiere esterne dell’Unione per l’attuazione dell’acquis di Schengen in materia di frontiere, visti e controllo delle frontiere esterne.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Risorse per le azioni specifiche", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In aggiunta alla dotazione calcolata secondo l’articolo 6, paragrafo 1, lettera a), agli Stati membri può essere assegnato un importo aggiuntivo, purché sia stanziato come tale nel programma nazionale e sia utilizzato per attuare le azioni specifiche elencate nell’allegato II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 17 per rivedere, se giudicato opportuno, l’elenco delle azioni specifiche riportato nell’allegato II, anche nel quadro della revisione intermedia. Sulla base delle nuove azioni specifiche, agli Stati membri può essere assegnato un importo aggiuntivo come previsto al paragrafo 1 del presente articolo, compatibilmente con le risorse disponibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’importo aggiuntivo di cui al presente articolo è assegnato ai singoli Stati membri con decisioni individuali di finanziamento che ne approvano o rivedono il rispettivo programma nazionale secondo la procedura di cui all’articolo 14 del regolamento (UE) n. 514/2014.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Risorse nell’ambito della revisione intermedia", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per assegnare l’importo indicato all’articolo 6, paragrafo 1, lettera c), entro il 1<span class=\"superscript\">o</span> giugno 2017 la Commissione tiene conto dell’onere sostenuto dagli Stati membri nella gestione delle frontiere, anche nell’ambito di attività di ricerca e soccorso che possono presentarsi durante un’operazione di sorveglianza di frontiera in mare o nell’ambito di relazioni di valutazione elaborate nel quadro del meccanismo di valutazione e monitoraggio Schengen, nonché dei livelli di minaccia alle frontiere esterne per il periodo 2017-2020 e dei fattori che hanno pregiudicato la sicurezza delle frontiere esterne nel periodo 2014-2016. Il suddetto importo è distribuito tra gli Stati membri sulla base della ponderazione delle seguenti categorie di frontiere, tenendo in considerazione il paragrafo 6 del presente articolo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 45 % per le frontiere marittime esterne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 38 % per le frontiere terrestri esterne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 17 % per gli aeroporti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le frontiere marittime e terrestri esterne il calcolo dell’importo è basato sulla lunghezza delle sezioni di frontiera esterna moltiplicata per un livello di minaccia (minimo, normale, medio, elevato) per ogni sezione di frontiera, come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coefficiente 0,5: minaccia minima;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coefficiente 1: minaccia normale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coefficiente 3: minaccia media;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coefficiente 5: minaccia elevata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per gli aeroporti, l’assegnazione è calcolata per ciascuno Stato membro come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 50 % in base al numero di persone che attraversano le frontiere esterne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 50 % in base al numero dei cittadini di paesi terzi cui è negato l’ingresso alle frontiere esterne.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In conformità della relazione di analisi dei rischi dell’agenzia Frontex e in consultazione con la stessa e, se del caso, con altre agenzie dell’Unione, la Commissione determina livelli di minaccia per ciascuna sezione di frontiera esterna degli Stati membri per il periodo 2017-2020. I livelli di minaccia si basano sui fattori seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">oneri nella gestione delle frontiere alle frontiere esterne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fattori che hanno inciso sulla sicurezza alle frontiere esterne degli Stati membri nel periodo 2014-2016;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cambiamenti nelle politiche dell’Unione, ad esempio nelle politiche in materia di visti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possibili tendenze future dei flussi migratori e dei rischi di attività illecite connesse all’attraversamento irregolare da parte di persone delle frontiere esterne; nonché</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">probabili sviluppi politici, economici e sociali nei paesi terzi, e in particolare nei paesi limitrofi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Prima di pubblicare la relazione in cui si determinano i livelli di minaccia, la Commissione procede a uno scambio di opinioni con gli Stati membri.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini della distribuzione delle risorse di cui al paragrafo 1:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si tiene conto della linea che separa le zone di cui all’articolo 1 del regolamento (CE) n. 866/2004 del Consiglio (\n<span class=\"superscript\">8</span>\n), anche se non costituisce una frontiera terrestre esterna, fintantoché si applica l’articolo 1 del protocollo n. 10 su Cipro all’atto di adesione del 2003, ma non della frontiera marittima a nord di tale linea;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con l’espressione «frontiere marittime esterne» si intende il limite esterno del mare territoriale degli Stati membri ai sensi degli articoli da 4 a 16 della convenzione delle Nazioni Unite sul diritto del mare. Tuttavia, nei casi in cui siano necessarie operazioni periodiche a lungo raggio per impedire attraversamenti di frontiera non autorizzati, per detta espressione si intende il limite esterno delle zone che presentano una minaccia elevata. Tali limiti esterni sono determinati tenendo conto dei pertinenti dati su tali operazioni nel periodo 2014-2016, forniti dagli Stati membri interessati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Inoltre, su invito della Commissione entro il 1<span class=\"superscript\">o</span> giugno 2017, agli Stati membri può essere assegnato un importo aggiuntivo, purché sia stanziato come tale nel programma nazionale e sia utilizzato per attuare le azioni specifiche da definire alla luce delle priorità dell’Unione a quella data.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’importo aggiuntivo di cui al presente articolo è assegnato ai singoli Stati membri con una decisione individuale di finanziamento che ne approva o rivede il rispettivo programma nazionale secondo la procedura di cui all’articolo 14 del regolamento (UE) n. 514/2014.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Programmi nazionali", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I programmi nazionali da redigere di cui allo strumento, tenendo conto dell’esito del dialogo politico di cui all’articolo 13 del regolamento (UE) n. 514/2014, congiuntamente con quello da elaborare in base al regolamento (UE) n. 513/2014 sono sottoposti alla Commissione sotto forma di un unico programma nazionale per il Fondo, a norma dell’articolo 14, del regolamento (UE) n. 514./2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito dei programmi nazionali, da sottoporre a esame e approvazione della Commissione a norma dell’articolo 14 del regolamento (UE) n. 514/2014, gli Stati membri, nel quadro degli obiettivi di cui all’articolo 3 del presente regolamento e tenendo conto dell’esito del dialogo politico di cui all’articolo 13 del regolamento (UE) n. 514/2014, perseguono in particolare obiettivi figuranti nel seguente elenco:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare Eurosur, in conformità del diritto e degli orientamenti dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere e ampliare la capacità esistente a livello nazionale nella politica dei visti e nella gestione delle frontiere esterne nonché delle misure all’interno dello spazio di libera circolazione relative alla gestione delle frontiere esterne, tenendo conto in particolare delle nuove tecnologie, degli sviluppi e/o gli standard in relazione alla gestione dei flussi migratori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’ulteriore sviluppo della gestione dei flussi migratori da parte dei servizi consolari o di altra natura degli Stati membri nei paesi terzi, compresa l’istituzione di meccanismi di cooperazione consolare al fine di facilitare i viaggi legittimi conformemente al diritto dell’Unione o dello Stato membro interessato e di prevenire l’immigrazione illegale nell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare la gestione integrata delle frontiere e l’introduzione di nuovi strumenti, sistemi interoperabili e metodi di lavoro volti a potenziare lo scambio di informazioni nel territorio dello Stato membro o per migliorare la cooperazione interservizi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare progetti al fine di garantire un livello elevato e uniforme di controllo delle frontiere esterne conformemente alle norme comuni dell’Unione e accrescere l’interoperabilità dei sistemi di gestione delle frontiere tra gli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere azioni, previa consultazione con l’agenzia Frontex, volte a promuovere un’ulteriore armonizzazione della gestione delle frontiere e in particolare le capacità tecnologiche, in conformità delle norme comuni dell’Unione;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼C2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire l’applicazione corretta e uniforme dell’acquis dell’Unione in materia di controllo di frontiera e visti in risposta alle carenze individuate a livello di Unione, come indicato nei risultati tratti nell’ambito del meccanismo di valutazione e monitoraggio Schengen;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">creare la capacità di far fronte a sfide imminenti, comprese le minacce e le sollecitazioni presenti e future alle frontiere esterne dell’Unione tenendo conto, in particolare, delle analisi effettuate da agenzie dell’Unione competenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nel perseguire gli obiettivi di cui al paragrafo 2, gli Stati membri possono sostenere, nell’ambito dei loro programmi nazionali, azioni in paesi terzi e nei confronti dei medesimi, anche attraverso la condivisione di informazioni e la cooperazione operativa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione consulta l’agenzia Frontex in merito ai progetti di programmi nazionali presentati dagli Stati membri, in particolare per quanto concerne le attività finanziate a titolo del supporto operativo, al fine di sviluppare la complementarità fra la missione dell’agenzia Frontex e le responsabilità degli Stati membri nel controllare e sorvegliare le frontiere esterne nonché al fine di garantire coerenza ed evitare inefficienza sotto il profilo dei costi.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Sostegno operativo nell’ambito dei programmi nazionali degli Stati membri", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può utilizzare fino al 40 % dell’importo stanziato nell’ambito dello strumento al suo programma nazionale per finanziare il sostegno operativo alle autorità pubbliche responsabili per la realizzazione dei compiti e dei servizi che costituiscono un servizio pubblico per l’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sostegno operativo è fornito se lo Stato membro interessato soddisfa le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformità all’acquis dell’Unione in materia di frontiere e visti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformità agli obiettivi del programma nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetto delle norme comuni dell’Unione, al fine di rafforzare il coordinamento tra gli Stati membri ed evitare duplicazioni, frammentazione e inefficienza dei costi nel settore del controllo delle frontiere.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">A tal fine, prima dell’approvazione del programma nazionale, la Commissione valuta la situazione di partenza negli Stati membri che hanno espresso l’intenzione di chiedere un sostegno operativo tenendo conto, ove pertinente, delle relazioni di valutazione Schengen.</div>\n</div>"], [null, "<p class=\"norm\">Le conclusioni della Commissione sono oggetto di uno scambio di opinioni con lo Stato membro interessato.</p>"], [null, "<p class=\"norm\">A seguito di tali discussioni, l’approvazione, da parte della Commissione, del sostegno di bilancio nell’ambito del programma nazionale di uno Stato membro può essere subordinata alla programmazione e al completamento di un certo numero di azioni volte a garantire che le condizioni di cui al paragrafo 2 sono pienamente soddisfatte prima dell’erogazione del sostegno finanziario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sostegno operativo si concentra su specifici compiti e/o servizi e si orienta al conseguimento degli obiettivi stabiliti nell’allegato III. Il sostegno comprende il rimborso integrale dei costi sostenuti per svolgere i compiti e/o servizi definiti nel programma nazionale, entro i limiti finanziari stabiliti dal programma e il massimale di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sostegno operativo è oggetto di monitoraggio e scambio di informazioni tra la Commissione e lo Stato membro interessato relativamente alla situazione di partenza nello Stato membro, agli obiettivi generali e specifici da realizzare e agli indicatori per misurare i progressi compiuti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, le procedure di rendicontazione dell’applicazione della presente disposizione e le eventuali altre modalità pratiche, da adottare tra gli Stati membri e la Commissione, per conformarsi al presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 18, paragrafo 2.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Sostegno operativo per il regime di transito speciale", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo strumento prevede un sostegno per compensare i diritti non riscossi per i visti di transito e i costi supplementari sostenuti per l’attuazione dei sistemi di documento di transito agevolato (FTD) e di documento di transito ferroviario agevolato (FRTD) ai sensi dei regolamenti (CE) n. 693/2003 e (CE) n. 694/2003 del Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le risorse assegnate alla Lituania a norma del paragrafo 1 non sono superiori a 154 milioni di EUR per il periodo dal 2014 al 2020 e sono rese disponibili come sostegno operativo supplementare specifico per la Lituania.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, per «costi supplementari» si intendono i costi che risultano direttamente dalle disposizioni specifiche di attuazione del regime di transito speciale e che non sono generati dal rilascio di visti di transito o per altre finalità.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Sono ammissibili al finanziamento i seguenti tipi di costi supplementari:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">investimenti infrastrutturali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formazione del personale addetto all’attuazione del regime di transito speciale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costi operativi supplementari, compresi gli stipendi del personale specificamente addetto all’attuazione del regime di transito speciale.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I diritti non riscossi di cui al paragrafo 1 del presente articolo sono calcolati sulla base del livello dei diritti di rilascio dei visti e dell’esenzione dal pagamento di tali diritti stabilita dall’accordo tra la Comunità europea e la Federazione russa di facilitazione del rilascio dei visti ai cittadini dell’Unione europea e della Federazione russa (\n<span class=\"superscript\">9</span>\n), nei limiti del quadro finanziario di cui al paragrafo 2 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione e la Lituania riesaminano l’applicazione del presente articolo qualora subentrino cambiamenti tali da incidere sull’esistenza e/o sul funzionamento del regime di transito speciale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, le procedure di rendicontazione dell’applicazione della presente disposizione e di eventuali provvedimenti finanziari o di altra natura pratica, da adottare tra la Lituania e la Commissione, al fine di conformarsi al presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 18, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per garantire il corretto funzionamento del regime di transito speciale la Commissione può adottare specifiche disposizioni relative al pagamento intermedio in deroga alle disposizioni del regolamento (UE) n. 514./2014.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Programmazione in linea con i risultati del meccanismo di valutazione e monitoraggio Schengen", "anchor": "art_12", "frags": [[null, "<p class=\"modref\">\n▼C2\n</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">A seguito della relazione di valutazione Schengen, adottata in conformità del regolamento (UE) n. 1053/2013, lo Stato membro interessato esamina, di concerto con la Commissione e con l’agenzia Frontex, le modalità per trattare le risultanze, comprese le eventuali carenze, e per attuare le raccomandazioni nell’ambito del suo programma nazionale.</p>"], [null, "<p class=\"norm\">Se necessario, lo Stato membro rivede il rispettivo programma nazionale a norma dell’articolo 14, paragrafo 9, del regolamento (CE) n. 514/2014 per tenere conto delle risultanze e raccomandazioni.</p>"], [null, "<p class=\"norm\">Il finanziamento delle azioni correttive è prioritario. Previa discussione con la Commissione e con l’agenzia Frontex, lo Stato membro interessato riattribuisce le risorse nell’ambito del programma, comprese quelle programmate per il sostegno operativo, e/o introduce o modifica le azioni volte ad ovviare alle carenze conformemente alle risultanze e alle raccomandazioni della relazione di valutazione Schengen.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Azioni dell’Unione", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione, lo strumento può finanziare azioni transnazionali o azioni di particolare interesse per l’Unione («azioni dell’Unione») riguardanti gli obiettivi generali, specifici e operativi di cui all’articolo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per essere ammissibili al finanziamento, le azioni dell’Unione perseguono, in particolare, i seguenti obiettivi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere attività preparatorie, di monitoraggio, di sostegno amministrativo e tecnico necessarie per attuare le politiche in materia di frontiere esterne e visti, compreso il rafforzamento della governance dell’area Schengen mettendo a punto e applicando il meccanismo di valutazione introdotto dal regolamento (UE) n. 1053/2013 per verificare l’applicazione dell’acquis di Schengen e il codice frontiere Schengen, in particolare le spese di missione per le visite in loco di esperti della Commissione e degli Stati membri partecipanti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">migliorare la conoscenza e la comprensione della situazione generale negli Stati membri e nei paesi terzi mediante l’analisi, la valutazione e l’attento controllo delle politiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere lo sviluppo di strumenti statistici, compresi strumenti statistici comuni, metodi e indicatori comuni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere e seguire l’attuazione del diritto e degli obiettivi politici dell’Unione negli Stati membri e valutarne l’efficacia e l’impatto, anche per quanto riguarda il rispetto dei diritti umani e delle libertà fondamentali, nella misura in cui ciò rientri nell’ambito di applicazione dello strumento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere il lavoro di rete, l’apprendimento reciproco, l’individuazione e la diffusione delle migliori prassi e di approcci innovativi tra i diversi soggetti interessati a livello europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere progetti miranti all’armonizzazione e all’interoperabilità delle misure connesse alla gestione delle frontiere conformemente alle norme comuni dell’Unione con l’obiettivo di sviluppare un sistema di gestione integrato delle frontiere europee;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sensibilizzare alle politiche e agli obiettivi dell’Unione presso gli organismi partecipanti e il pubblico in generale, compresa la comunicazione istituzionale sulle priorità politiche dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">migliorare la capacità delle reti di livello europeo di valutare, promuovere, sostenere e sviluppare ulteriormente le politiche dell’Unione e i suoi obiettivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere progetti particolarmente innovativi volti a sviluppare nuovi metodi e/o utilizzare nuove tecnologie con un potenziale di trasferibilità verso altri Stati membri, soprattutto progetti che mirano a verificare e convalidare progetti di ricerca;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere azioni nei paesi terzi e in relazione a tali paesi, di cui all’articolo 4, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le azioni dell’Unione sono attuate in conformità dell’articolo 6 del regolamento (UE) n. 514/2014.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Assistenza emergenziale", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo strumento presta sostegno finanziario per far fronte a necessità urgenti e specifiche nell’eventualità di una situazione di emergenza, come definita all’articolo 2, lettera f).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’assistenza emergenziale è attuata in conformità degli articoli 6 e 7 del regolamento (UE) n. 514/2014.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Definizione di un programma per lo sviluppo di sistemi informatici", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Il programma sullo sviluppo di sistemi informatici basati su sistemi informatici attuali e/o nuovi è attuato previa adozione di atti legislativi dell’Unione che definiscono tali sistemi informatici e le loro infrastrutture di comunicazione, segnatamente con l’obiettivo di migliorare la gestione e il controllo dei flussi di attraversamento delle frontiere esterne rafforzando le verifiche e, al contempo, facilitando il passaggio di frontiera ai viaggiatori in regola. Ove opportuno, si garantiscono sinergie con i sistemi informatici esistenti al fine di evitare doppioni di spesa.</p>"], [null, "<p class=\"norm\">La ripartizione della dotazione di cui all’articolo 5, paragrafo 5, lettera b), è definita nei pertinenti atti legislativi dell’Unione oppure, previa adozione di tali atti legislativi, mediante un atto delegato conformemente all’articolo 17.</p>"], [null, "<p class=\"norm\">La Commissione informa il Parlamento europeo e il Consiglio dei progressi compiuti nello sviluppo di tali sistemi informatici almeno una volta all’anno e ogniqualvolta sia opportuno.</p>"]]}, "16": {"label": "Articolo 16", "heading": "Assistenza tecnica", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione e/o per suo conto, lo strumento può contribuire annualmente, nel limite di 1,7 milioni di EUR, all’assistenza tecnica prevista dal Fondo Sicurezza interna, in conformità dell’articolo 9 del regolamento (UE) n. 514/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Su iniziativa di uno Stato membro, il Fondo può finanziare attività di assistenza tecnica in conformità dell’articolo 20 del regolamento (UE) n. 514/2014. L’importo stanziato per l’assistenza tecnica per il periodo 2014-2020 non supera il 5 % dell’importo totale assegnato agli Stati membri maggiorato di 500 000  EUR.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "17": {"label": "Articolo 17", "heading": "Esercizio della delega", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 5, paragrafo 5, lettera b), all’articolo 6, paragrafo 4, all’articolo 7, paragrafo 2, e all’articolo 15 è conferito alla Commissione per un periodo di sette anni a decorrere da .21 maggio 2014. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di sette anni. La delega di potere è tacitamente prorogata per un periodo di tre anni, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo settennale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 5, paragrafo 5, lettera b), all’articolo 6, paragrafo 4, all’articolo 7, paragrafo 2, e all’articolo 15 può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega del potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 5, paragrafo 5, lettera b), all’articolo 6, paragrafo 4, all’articolo 7, paragrafo 2, e all’articolo 15 entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale periodo è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Procedura di comitato", "anchor": "art_18", "frags": [[null, "<p class=\"modref\">\n▼C1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita dal «comitato Fondi Asilo, migrazione e integrazione e Sicurezza interna» istituito a norma dell'articolo 59, paragrafo 1, del regolamento (UE) n. 514/2014.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Applicabilità del regolamento (UE) n. 514/2014", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">Allo strumento si applicano le disposizioni del regolamento (UE) n. 514/2014.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Abrogazione", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">La decisione n. 574/2007/CE è abrogata con effetto dal 1<span class=\"superscript\">o</span> gennaio 2014.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Disposizioni transitorie", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento non pregiudica il proseguimento o la modifica, compresa la soppressione totale o parziale, dei progetti e dei programmi annuali, fino alla loro chiusura, o di interventi approvati dalla Commissione sulla base della decisione 574/2007/CE o di qualsivoglia altra norma applicabile a tali interventi alla data del 31 dicembre 2013.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nell’adottare decisioni di cofinanziamento ai sensi dello strumento, la Commissione tiene conto delle misure adottate sulla base della decisione 574/2007/CE prima del 20 maggio 2014 aventi un’incidenza finanziaria nel periodo di riferimento del cofinanziamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli importi impegnati per il cofinanziamento, approvati dalla Commissione tra il 1<span class=\"superscript\">o</span> gennaio 2011 e il 31 dicembre 2014 e per i quali non le sono stati trasmessi i documenti richiesti per la chiusura delle azioni entro il termine previsto per la presentazione della relazione finale, sono disimpegnati automaticamente dalla Commissione entro il 31 dicembre 2017 e danno luogo al rimborso degli importi indebitamente versati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sono esclusi dal calcolo dell’importo da disimpegnare automaticamente gli importi corrispondenti ad azioni sospese a causa di procedimenti giudiziari o ricorsi amministrativi con effetto sospensivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Entro il 30 giugno 2015 gli Stati membri presentano alla Commissione la relazione di valutazione dei risultati e dell’impatto delle azioni cofinanziate ai sensi della decisione n. 574/2007/CE per il periodo 2011-2013.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione presenta al Parlamento europeo, al Consiglio, al Comitato economico e sociale europeo e al Comitato delle regioni, entro il 31 dicembre 2015, la relazione di valutazione ex post ai sensi della decisione 574/2007/CE relativamente al periodo 2011-2013.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Revisione", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">Su proposta della Commissione, il Parlamento europeo e il Consiglio riesaminano il presente regolamento entro il 30 giugno 2020.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Entrata in vigore e applicazione", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno successivo a quello della sua pubblicazione nella Gazzetta <span class=\"italics\">ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2014.</p>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri conformemente ai trattati.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};